class ProductionLine
{
    public string Name;
    public double Temperature;
    public bool MotorRunning;
    public bool HeaterOn;
    public ProductionLine(string n, double t) { Name = n; Temperature = t; }
}

var lineA = new ProductionLine("产线A", 25);
lineA.MotorRunning = true;
var lineB = new ProductionLine("产线B", 33);
lineB.HeaterOn = true;
var lineC = new ProductionLine("产线C", 28);
lineC.MotorRunning = true;

var lines = new List<ProductionLine>();
lines.Add(lineA); lines.Add(lineB); lines.Add(lineC);

void CheckLine(ProductionLine line)
{
    Print($"{line.Name}: {line.Temperature}°C 电机:{(line.MotorRunning?"运行":"停止")} 加热:{(line.HeaterOn?"开启":"关闭")}");
    if (line.Temperature > 30) Print("  ⚠ 异常！");
}

int abnormal = 0;
foreach (var line in lines)
{
    CheckLine(line);
    if (line.Temperature > 30) abnormal++;
}

Print($"异常产线: {abnormal}");
Print("===== 巡检完成 =====");
